import{_ as l,C as e,o as s,c as i,a2 as t,E as d}from"./chunks/framework.Do_4EYrn.js";const b=JSON.parse('{"title":"附录 F 备份、校验与恢复演练","description":"备份的价值由恢复结果决定。看到“复制完成”或“同步成功”只能说明流程执行过；只有校验通过，并且资产已经在新的空目录中恢复且能够继续使用，才能证明恢复链路有效。 本附录提供通用治理方法，不指定公司正式存储系统、保留周期或恢复责任。具体位置、权限、保密要求和恢复目标应由信息化、安全、业务和资料责任人共同确认。","frontmatter":{},"headers":[],"relativePath":"bluebook/附录/附录 F 备份、校验与恢复演练/index.md","filePath":"bluebook/附录/附录 F 备份、校验与恢复演练/index.md","lastUpdated":1784290813000}'),r={name:"bluebook/附录/附录 F 备份、校验与恢复演练/index.md"};function p(o,a,E,h,A,c){const n=e("MermaidDiagram");return s(),i("div",null,[a[0]||(a[0]=t('<h1 id="附录-f-备份、校验与恢复演练" tabindex="-1">附录 F 备份、校验与恢复演练 <a class="header-anchor" href="#附录-f-备份、校验与恢复演练" aria-label="Permalink to &quot;附录 F 备份、校验与恢复演练&quot;">​</a></h1><p>备份的价值由恢复结果决定。看到“复制完成”或“同步成功”只能说明流程执行过；只有校验通过，并且资产已经在新的空目录中恢复且能够继续使用，才能证明恢复链路有效。</p><p>本附录提供通用治理方法，不指定公司正式存储系统、保留周期或恢复责任。具体位置、权限、保密要求和恢复目标应由信息化、安全、业务和资料责任人共同确认。</p><h2 id="需要保护哪些-ai-协作资产" tabindex="-1">需要保护哪些 AI 协作资产 <a class="header-anchor" href="#需要保护哪些-ai-协作资产" aria-label="Permalink to &quot;需要保护哪些 AI 协作资产&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资产类别</th><th>建议纳入范围</th><th>恢复后检查什么</th></tr></thead><tbody><tr><td>成果资产</td><td>正式文件、项目数据、代码、图片及验收记录</td><td>文件可打开，数量、版本和关键内容一致</td></tr><tr><td>协作资产</td><td>任务规则、模板、Skill、已确认记忆和维护说明</td><td>Agent 能读取正确版本，规则和来源关系完整</td></tr><tr><td>连续性资产</td><td>快照、文件清单、校验结果、恢复说明和演练记录</td><td>能找到可用时间点，恢复步骤和责任人清楚</td></tr></tbody></table><p>密钥、Token、密码、私钥、个人账号文件、缓存和原始会话记录默认排除。确需备份的敏感配置应使用公司批准的凭证管理和加密方案，不得混入普通协作资产包。</p><h2 id="备份、同步和恢复分别解决什么" tabindex="-1">备份、同步和恢复分别解决什么 <a class="header-anchor" href="#备份、同步和恢复分别解决什么" aria-label="Permalink to &quot;备份、同步和恢复分别解决什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>主要作用</th><th>需要注意的限制</th></tr></thead><tbody><tr><td>工作目录</td><td>保存当前正在使用的最新状态</td><td>误删、误改会立即影响正式资产</td></tr><tr><td>同步</td><td>在设备或服务之间保持接近一致的状态</td><td>删除和错误也可能被同步传播</td></tr><tr><td>时间点快照</td><td>保留多个独立历史状态</td><td>同盘快照无法应对整块磁盘损坏</td></tr><tr><td>异地副本</td><td>应对设备、磁盘或单一位置不可用</td><td>必须使用公司批准的位置和访问权限</td></tr><tr><td>恢复演练</td><td>证明快照完整、步骤可执行、工作能够接续</td><td>应恢复到新位置并记录验收结果</td></tr></tbody></table><p>一个可靠方案通常同时保留当前工作目录、多个独立时间点和经过批准的第二位置，并定期做恢复演练。</p><h2 id="六步闭环" tabindex="-1">六步闭环 <a class="header-anchor" href="#六步闭环" aria-label="Permalink to &quot;六步闭环&quot;">​</a></h2><h3 id="_1-建立资产与责任清单" tabindex="-1">1. 建立资产与责任清单 <a class="header-anchor" href="#_1-建立资产与责任清单" aria-label="Permalink to &quot;1. 建立资产与责任清单&quot;">​</a></h3><p>列出需要保护的目录、文件类型、负责人、敏感级别、更新频率、允许存放的位置和恢复优先级。没有明确来源或无权保存的材料不得擅自纳入。</p><h3 id="_2-生成独立时间点快照" tabindex="-1">2. 生成独立时间点快照 <a class="header-anchor" href="#_2-生成独立时间点快照" aria-label="Permalink to &quot;2. 生成独立时间点快照&quot;">​</a></h3><p>快照放在工作目录之外，使用日期和批次形成独立目录。生成时记录成功、跳过、排除和失败项；重复运行不能静默覆盖已有快照。</p><h3 id="_3-生成并检查校验清单" tabindex="-1">3. 生成并检查校验清单 <a class="header-anchor" href="#_3-生成并检查校验清单" aria-label="Permalink to &quot;3. 生成并检查校验清单&quot;">​</a></h3><p>为快照生成文件路径、数量、大小和哈希等校验信息。校验要能发现缺失、损坏和意外新增的敏感文件。看到脚本退出成功仍需检查清单和日志。</p><h3 id="_4-管理保留周期和第二位置" tabindex="-1">4. 管理保留周期和第二位置 <a class="header-anchor" href="#_4-管理保留周期和第二位置" aria-label="Permalink to &quot;4. 管理保留周期和第二位置&quot;">​</a></h3><p>根据资产变化频率和恢复目标保留多个时间点。需要应对磁盘、设备或办公地点故障时，将快照复制到公司批准的第二介质或异地存储；不得自行上传到个人云盘或未批准服务。</p><h3 id="_5-恢复到新的空目录" tabindex="-1">5. 恢复到新的空目录 <a class="header-anchor" href="#_5-恢复到新的空目录" aria-label="Permalink to &quot;5. 恢复到新的空目录&quot;">​</a></h3><p>选择一个已校验快照，恢复到不包含现有文件的目标目录。演练阶段不覆盖正式工作区，也不直接写回 Agent 的用户级配置。</p><h3 id="_6-验收并留下演练记录" tabindex="-1">6. 验收并留下演练记录 <a class="header-anchor" href="#_6-验收并留下演练记录" aria-label="Permalink to &quot;6. 验收并留下演练记录&quot;">​</a></h3><p>至少完成以下检查：</p><ul><li>资产目录和必需文件完整，文件数量与校验清单一致。</li><li>抽样文件可以打开，关键数据、版本和引用关系正确。</li><li>至少一个模板或 Skill 能被读取并完成脱敏测试任务。</li><li>已确认记忆、来源、状态和适用范围能够继续查询。</li><li>Agent 可以根据恢复后的规则接续一个测试任务。</li><li>演练日期、快照时间、执行人、验收人、问题和修正措施已经记录。</li></ul><h2 id="恢复演练流程" tabindex="-1">恢复演练流程 <a class="header-anchor" href="#恢复演练流程" aria-label="Permalink to &quot;恢复演练流程&quot;">​</a></h2>',24)),d(n,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E9%80%89%E6%8B%A9%E5%8F%AF%E4%BF%A1%E5%BF%AB%E7%85%A7%5D%20--%3E%20B%5B%E6%A0%B8%E5%AF%B9%E6%B8%85%E5%8D%95%E4%B8%8E%E6%A0%A1%E9%AA%8C%E5%80%BC%5D%0A%20%20%20%20B%20--%3E%20C%7B%E6%A0%A1%E9%AA%8C%E9%80%9A%E8%BF%87%3F%7D%0A%20%20%20%20C%20--%20%E5%90%A6%20--%3E%20D%5B%E5%81%9C%E6%AD%A2%E5%B9%B6%E6%8A%A5%E5%91%8A%E7%BC%BA%E5%A4%B1%E6%88%96%E6%8D%9F%E5%9D%8F%5D%0A%20%20%20%20C%20--%20%E6%98%AF%20--%3E%20E%5B%E6%81%A2%E5%A4%8D%E5%88%B0%E6%96%B0%E7%9A%84%E7%A9%BA%E7%9B%AE%E5%BD%95%5D%0A%20%20%20%20E%20--%3E%20F%5B%E6%A3%80%E6%9F%A5%E6%96%87%E4%BB%B6%E3%80%81Skill%E3%80%81%E8%AE%B0%E5%BF%86%E4%B8%8E%E4%BB%BB%E5%8A%A1%E6%8E%A5%E7%BB%AD%5D%0A%20%20%20%20F%20--%3E%20G%7B%E9%AA%8C%E6%94%B6%E9%80%9A%E8%BF%87%3F%7D%0A%20%20%20%20G%20--%20%E5%90%A6%20--%3E%20H%5B%E8%AE%B0%E5%BD%95%E9%97%AE%E9%A2%98%E5%B9%B6%E4%BF%AE%E6%AD%A3%E5%A4%87%E4%BB%BD%E6%96%B9%E6%A1%88%5D%0A%20%20%20%20G%20--%20%E6%98%AF%20--%3E%20I%5B%E5%BD%92%E6%A1%A3%E6%BC%94%E7%BB%83%E8%AE%B0%E5%BD%95%E5%92%8C%E5%8F%AF%E7%94%A8%E6%81%A2%E5%A4%8D%E7%82%B9%5D%0A"}),a[1]||(a[1]=t(`<h2 id="可复制恢复演练模板" tabindex="-1">可复制恢复演练模板 <a class="header-anchor" href="#可复制恢复演练模板" aria-label="Permalink to &quot;可复制恢复演练模板&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请对这份 AI 协作资产快照执行只读校验和恢复演练。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>快照位置：{位置}</span></span>
<span class="line"><span>恢复目标：{必须为空的新目录}</span></span>
<span class="line"><span>资产责任人：{责任人}</span></span>
<span class="line"><span>本次验收人：{验收人}</span></span>
<span class="line"><span>允许读取范围：{范围}</span></span>
<span class="line"><span>禁止写入范围：{正式目录、用户级配置、外部系统等}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请按以下步骤执行：</span></span>
<span class="line"><span>1. 检查快照目录、文件数量、校验清单和日志；</span></span>
<span class="line"><span>2. 发现缺失、损坏、敏感文件或路径异常时立即停止；</span></span>
<span class="line"><span>3. 校验通过后恢复到指定空目录，不覆盖现有目录；</span></span>
<span class="line"><span>4. 检查必需文件，并抽样打开成果文件；</span></span>
<span class="line"><span>5. 检查一个模板或 Skill、已确认记忆及其来源关系；</span></span>
<span class="line"><span>6. 使用恢复目录完成一个脱敏测试任务；</span></span>
<span class="line"><span>7. 输出演练结果、问题清单、可用恢复点和修正建议。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>没有责任人确认，不替换正式目录，不恢复账号凭证，不重新开启自动化。</span></span></code></pre></div><h2 id="发生事故后的恢复顺序" tabindex="-1">发生事故后的恢复顺序 <a class="header-anchor" href="#发生事故后的恢复顺序" aria-label="Permalink to &quot;发生事故后的恢复顺序&quot;">​</a></h2><ol><li>停止仍在运行的 Agent、脚本、同步和自动重试。</li><li>保护现场日志、受影响目录和时间信息，避免继续写入。</li><li>确认最近一个未受影响且校验通过的快照。</li><li>在新的空目录恢复并完成验收。</li><li>由责任人确认业务影响、丢失范围和正式恢复方案。</li><li>替换正式资产前再次建立当前现场副本，保留调查和回退能力。</li><li>恢复完成后收回临时权限，修正触发条件、备份范围或处置流程。</li></ol><h2 id="常见弯路与安全边界" tabindex="-1">常见弯路与安全边界 <a class="header-anchor" href="#常见弯路与安全边界" aria-label="Permalink to &quot;常见弯路与安全边界&quot;">​</a></h2><ul><li>只检查备份任务显示“成功”，无法发现文件缺失、排除规则错误和快照损坏。</li><li>把同步目录当作唯一恢复来源，误删和误改可能已经传播到所有设备。</li><li>只保留最新一份副本，发现问题较晚时无法回到更早的可信状态。</li><li>在正式目录上直接测试恢复，会覆盖现场并扩大影响。恢复演练必须使用空目录。</li><li>未检查敏感文件排除结果，可能把凭证和个人信息复制到更广范围。</li><li>备份位置、访问权限、保留期限和销毁方式必须符合公司制度和第三方材料授权。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>快照包含经过确认的资产范围，并有清单、校验值和运行日志。</li><li>至少保留多个可识别时间点，第二位置符合公司批准范围。</li><li>恢复操作在空目录完成，没有覆盖正式资产和用户级配置。</li><li>文件、Skill、记忆和测试任务均通过验收。</li><li>演练记录能够说明使用了哪个快照、发现了什么问题、由谁确认和怎样修正。</li></ul>`,8))])}const u=l(r,[["render",p]]);export{b as __pageData,u as default};
